// src/context/AuthContext.js
import React, { createContext, useContext, useState } from "react";
import { MOCK_FRIENDS } from "../data/mockData";

const AuthContext = createContext();
export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(() =>
    JSON.parse(localStorage.getItem("ss_user")) || null
  );

  const [users, setUsers] = useState(() =>
    JSON.parse(localStorage.getItem("ss_users")) || []
  );

  // Network = friend IDs the current user has added
  const [network, setNetwork] = useState(() =>
    JSON.parse(localStorage.getItem("ss_network")) || MOCK_FRIENDS.map((f) => f.id)
  );

  // Theme: 'dark' | 'light'
  const [theme, setTheme] = useState(() =>
    localStorage.getItem("ss_theme") || "dark"
  );

  const toggleTheme = () => {
    const next = theme === "dark" ? "light" : "dark";
    setTheme(next);
    localStorage.setItem("ss_theme", next);
  };

  const signup = (newUser) => {
    const updatedUsers = [...users, newUser];
    setUsers(updatedUsers);
    localStorage.setItem("ss_users", JSON.stringify(updatedUsers));
    setUser(newUser);
    localStorage.setItem("ss_user", JSON.stringify(newUser));
  };

  const login = (email, password) => {
    // Allow demo login with any non-empty credentials
    const foundUser = users.find(
      (u) => u.email === email && u.password === password
    );
    if (foundUser) {
      setUser(foundUser);
      localStorage.setItem("ss_user", JSON.stringify(foundUser));
      return true;
    }
    // Demo fallback
    if (email && password) {
      const demoUser = {
        id: "demo",
        name: email.split("@")[0].replace(/[._]/g, " ").replace(/\b\w/g, (c) => c.toUpperCase()),
        email,
        avatar: email[0].toUpperCase(),
        skillsOffered: ["React", "JavaScript"],
        skillsWanted: ["Machine Learning"],
        stats: { swaps: 3, rating: 4.5, reviews: 6 },
      };
      setUser(demoUser);
      localStorage.setItem("ss_user", JSON.stringify(demoUser));
      return true;
    }
    return false;
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem("ss_user");
  };

  const addToNetwork = (userId) => {
    const updated = [...network, userId];
    setNetwork(updated);
    localStorage.setItem("ss_network", JSON.stringify(updated));
  };

  const removeFromNetwork = (userId) => {
    const updated = network.filter((id) => id !== userId);
    setNetwork(updated);
    localStorage.setItem("ss_network", JSON.stringify(updated));
  };

  const isInNetwork = (userId) => network.includes(userId);

  return (
    <AuthContext.Provider
      value={{
        user, users, login, logout, signup,
        network, addToNetwork, removeFromNetwork, isInNetwork,
        theme, toggleTheme,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};
